import React from "react";
import styles from "./card-bg.module.css";
import Title from "../../../title";
import Button from "../../../button";
import { useTranslation } from "react-i18next";

const CardBg: React.FC = () => {
  const [t, i18n] = useTranslation("global");
  const HandleChangeLanguage = (lang: string) => {
    i18n.changeLanguage(lang);
  };
  return (
    <div className={styles.card_bg}>
      <div className={styles.title_icon}>🌱</div>
      <Title level="h1" className={styles.title}>
        {t("home.title")}
      </Title>
      <p className={styles.desc}>
        All handmade with natural soy wax, Candleaf is a companion for all your
        pleasure moments
      </p>
      <div className={styles.wrapper_button}>
        <Button text="Discovery our collection" href="#" />
        <button onClick={() => HandleChangeLanguage('en')}></button>
      </div>
    </div>
  );
};

export default CardBg;
